const nombre = $('Preparar Datos').first().json.Nombre || "anonimo";
const output = $input.first().json.output || "sin-plan";

// Devolvemos un JSON limpio con nombres de propiedades seguros
return [
  {
    json: {
      id_cliente: sessionId,
      nombre_cliente: nombre,
      contenido_plan: output
    }
  }
];

